import os
import anthropic
from PyPDF2 import PdfReader
import textwrap

class PaperSummarizer:
    def __init__(self, api_key=None):
        self.client = anthropic.Client(api_key or os.getenv("ANTHROPIC_API_KEY"))
        self.summaries = {}
        self.papers = {}

    def load_paper(self, file_path):
        """Load and extract text from a PDF paper"""
        try:
            with open(file_path, "rb") as f:
                reader = PdfReader(f)
                text = "\n".join([page.extract_text() for page in reader.pages])
                paper_id = os.path.basename(file_path)
                self.papers[paper_id] = text
                return paper_id
        except Exception as e:
            print(f"Error loading paper: {e}")
            return None

    def summarize_paper(self, paper_id, model="claude-2", max_tokens=1000):
        """Generate a summary of the paper using Claude"""
        if paper_id not in self.papers:
            print("Paper not found")
            return None

        paper_text = self.papers[paper_id]
        prompt = f"""Here is a research paper:

        {paper_text[:20000]}  # Truncate to avoid token limits

        Please provide a concise summary covering:
        1. Key research question
        2. Methodology
        3. Main findings
        4. Significance

        Summary:"""

        try:
            response = self.client.completion(
                prompt=prompt,
                model=model,
                max_tokens_to_sample=max_tokens,
                stop_sequences=[anthropic.HUMAN_PROMPT]
            )
            summary = response["completion"]
            self.summaries[paper_id] = summary
            return summary
        except Exception as e:
            print(f"Error generating summary: {e}")
            return None

    def query_summary(self, paper_id, question):
        """Ask a question about a summarized paper"""
        if paper_id not in self.summaries:
            print("Summary not found")
            return None

        summary = self.summaries[paper_id]
        prompt = f"""Here is a summary of a research paper:

        {summary}

        Question: {question}

        Answer:"""

        try:
            response = self.client.completion(
                prompt=prompt,
                model="claude-2",
                max_tokens_to_sample=500
            )
            return response["completion"]
        except Exception as e:
            print(f"Error querying summary: {e}")
            return None

    def interactive_mode(self):
        """Run an interactive session with the user"""
        print("Paper Summarizer - Interactive Mode")
        print("Commands: load <path>, summarize <id>, query <id> <question>, exit")

        while True:
            cmd = input("> ").strip().split()
            if not cmd:
                continue

            if cmd[0] == "exit":
                break

            elif cmd[0] == "load" and len(cmd) > 1:
                paper_id = self.load_paper(" ".join(cmd[1:]))
                if paper_id:
                    print(f"Loaded paper with ID: {paper_id}")

            elif cmd[0] == "summarize" and len(cmd) > 1:
                summary = self.summarize_paper(cmd[1])
                if summary:
                    print("\nSummary:")
                    print(textwrap.fill(summary, width=80))

            elif cmd[0] == "query" and len(cmd) > 2:
                answer = self.query_summary(cmd[1], " ".join(cmd[2:]))
                if answer:
                    print("\nAnswer:")
                    print(textwrap.fill(answer, width=80))

            else:
                print("Invalid command")

if __name__ == "__main__":
    summarizer = PaperSummarizer()
    summarizer.interactive_mode()

import os
import anthropic
from PyPDF2 import PdfReader
import textwrap

class PaperSummarizer:
    def __init__(self, api_key=None):
        self.client = anthropic.Client(api_key or os.getenv("ANTHROPIC_API_KEY"))
        self.summaries = {}
        self.paper_texts = {}

    def load_paper(self, file_path):
        """Load text from a PDF paper"""
        with open(file_path, 'rb') as file:
            reader = PdfReader(file)
            text = "\n".join([page.extract_text() for page in reader.pages])
            paper_id = os.path.basename(file_path)
            self.paper_texts[paper_id] = text
            return paper_id

    def summarize_paper(self, paper_id, model="claude-2", max_tokens=1000):
        """Generate a summary of the paper using Claude"""
        if paper_id not in self.paper_texts:
            raise ValueError("Paper not loaded")

        text = self.paper_texts[paper_id]
        prompt = f"""Human: Please summarize the following academic paper in clear, concise terms. 
        Focus on the key contributions, methodology, and findings. Keep it under {max_tokens} tokens.

        Paper:
        {textwrap.shorten(text, width=100000, placeholder="...")}

        Assistant:"""

        response = self.client.completion(
            prompt=prompt,
            model=model,
            max_tokens_to_sample=max_tokens
        )

        summary = response['completion']
        self.summaries[paper_id] = summary
        return summary

    def ask_question(self, paper_id, question, model="claude-2", max_tokens=500):
        """Ask a question about a summarized paper"""
        if paper_id not in self.summaries:
            raise ValueError("Paper not summarized")

        prompt = f"""Human: Here is a summary of a research paper:
        {self.summaries[paper_id]}

        Question: {question}

        Please answer based on the summary. If the answer isn't clear from the summary, say so.

        Assistant:"""

        response = self.client.completion(
            prompt=prompt,
            model=model,
            max_tokens_to_sample=max_tokens
        )

        return response['completion']

    def interactive_session(self):
        """Run an interactive session with the user"""
        print("Paper Summarizer - Interactive Mode")
        while True:
            print("\nOptions:")
            print("1. Load a paper (PDF)")
            print("2. Summarize a loaded paper")
            print("3. Ask a question about a summary")
            print("4. Exit")

            choice = input("Enter your choice (1-4): ")

            if choice == "1":
                path = input("Enter PDF file path: ")
                try:
                    paper_id = self.load_paper(path)
                    print(f"Paper loaded with ID: {paper_id}")
                except Exception as e:
                    print(f"Error loading paper: {e}")

            elif choice == "2":
                paper_id = input("Enter paper ID to summarize: ")
                try:
                    summary = self.summarize_paper(paper_id)
                    print("\nSummary:")
                    print(summary)
                except Exception as e:
                    print(f"Error summarizing: {e}")

            elif choice == "3":
                paper_id = input("Enter paper ID: ")
                question = input("Enter your question: ")
                try:
                    answer = self.ask_question(paper_id, question)
                    print("\nAnswer:")
                    print(answer)
                except Exception as e:
                    print(f"Error answering question: {e}")

            elif choice == "4":
                print("Exiting...")
                break

            else:
                print("Invalid choice, please try again.")

if __name__ == "__main__":
    api_key = input("Enter your Anthropic API key (or press Enter to use ANTHROPIC_API_KEY env var): ")
    summarizer = PaperSummarizer(api_key if api_key else None)
    summarizer.interactive_session()
